    #[test]
    fn extracts_command_interface_subsystems_order() {
        let first_uuid = "aaaaaaaa-aaaa-4aaa-aaaa-aaaaaaaaaaaa";
        let second_uuid = "bbbbbbbb-bbbb-4bbb-bbbb-bbbbbbbbbbbb";
        let body =
            deflate_for_test(format!("{{7,0,0,0,1,2,{first_uuid},{second_uuid},0,0}}").as_bytes());
        let metadata_refs = BTreeMap::from([
            (
                first_uuid.to_string(),
                MetadataCommandReference {
                    kind: "Subsystem".to_string(),
                    name: "Sales".to_string(),
                },
            ),
            (
                second_uuid.to_string(),
                MetadataCommandReference {
                    kind: "Subsystem".to_string(),
                    name: "Purchases".to_string(),
                },
            ),
        ]);

        let command_interface =
            parse_command_interface_blob(&body, &BTreeMap::new(), &metadata_refs).unwrap();
        let xml = format_command_interface_xml(&command_interface);

        assert!(xml.contains("<SubsystemsOrder>"));
        assert!(xml.contains("<Subsystem>Subsystem.Sales</Subsystem>"));
        assert!(xml.contains("<Subsystem>Subsystem.Purchases</Subsystem>"));
        assert!(!xml.contains("<CommandsVisibility>"));
    }

    #[test]
    fn extracts_command_interface_visibility_placement_order_and_groups() {
        let command_uuid = "aaaaaaaa-aaaa-4aaa-aaaa-aaaaaaaaaaaa";
        let group_uuid = "1af6d528-0b86-4fba-ab95-bd7475db03ba";
        let body = deflate_for_test(
            format!(
                "{{7,1,1,{{0,{command_uuid}}},{{0,{{0,{{\"B\",1}},0}}}},1,1,{{0,{command_uuid}}},{group_uuid},1,1,1,{group_uuid},{{0,{command_uuid}}},0,1,1,{group_uuid},0}}"
            )
            .as_bytes(),
        );
        let command_refs = BTreeMap::from([(
            command_uuid.to_string(),
            "CommonCommand.OpenDashboard".to_string(),
        )]);

        let command_interface =
            parse_command_interface_blob(&body, &command_refs, &BTreeMap::new()).unwrap();
        let xml = format_command_interface_xml(&command_interface);

        assert!(xml.contains("<CommandsVisibility>"));
        assert!(xml.contains("<CommandsPlacement>"));
        assert!(xml.contains("<Placement>Manual</Placement>"));
        assert!(xml.contains("<CommandsOrder>"));
        assert!(xml.contains("<GroupsOrder>"));
        assert!(xml.contains("<Group>NavigationPanelImportant</Group>"));
        assert!(
            xml.find("<CommandsVisibility>").unwrap() < xml.find("<CommandsPlacement>").unwrap()
        );
        assert!(xml.find("<CommandsPlacement>").unwrap() < xml.find("<CommandsOrder>").unwrap());
    }

    #[test]
    fn extracts_standalone_content_used_items() {
        let first_uuid = "aaaaaaaa-aaaa-4aaa-aaaa-aaaaaaaaaaaa";
        let second_uuid = "bbbbbbbb-bbbb-4bbb-bbbb-bbbbbbbbbbbb";
        let body = deflate_for_test(format!("{{2,2,{first_uuid},{second_uuid},0}}").as_bytes());
        let references = StandaloneContentReferences {
            object_refs: BTreeMap::from([
                (first_uuid.to_string(), "Role.ReadOnlyUsers".to_string()),
                (
                    second_uuid.to_string(),
                    "CommonCommand.OpenAllReports".to_string(),
                ),
            ]),
        };

        let xml =
            String::from_utf8(extract_standalone_content_xml(&body, &references).unwrap()).unwrap();

        assert!(xml.starts_with("\u{feff}<?xml version=\"1.0\" encoding=\"UTF-8\"?>"));
        assert!(xml.contains("<StandaloneContent"));
        assert!(xml.contains("<Metadata>Role.ReadOnlyUsers</Metadata>"));
        assert!(xml.contains("<Metadata>CommonCommand.OpenAllReports</Metadata>"));
        assert!(
            xml.find("Role.ReadOnlyUsers").unwrap()
                < xml.find("CommonCommand.OpenAllReports").unwrap()
        );
    }

    #[test]
    fn source_asset_only_dump_resolves_standalone_content_refs() {
        let root = std::env::temp_dir().join(format!(
            "ibcmd-rs-standalone-content-source-only-{}",
            uuid::Uuid::new_v4().hyphenated()
        ));
        fs::create_dir_all(&root).unwrap();
        let configuration_uuid = "aaaaaaaa-aaaa-4aaa-aaaa-aaaaaaaaaaaa";
        let role_uuid = "0014cc2a-b5ed-427d-8ac6-116e92aaa9a4";
        let module = pack_module_blob_bytes(b"", None, None).unwrap().blob;
        let parent_configurations = deflate_for_test(b"{6,0}");
        let standalone = deflate_for_test(format!("{{2,1,{role_uuid},0}}").as_bytes());
        let role_metadata = deflate_for_test(
            format!(
                "{{1,\r\n{{6,\r\n{{3,\r\n{{1,0,{role_uuid}}},\"TargetMetrics\",{{1,\"en\",\"Target metrics\"}},\"\"}},0}}\r\n}}"
            )
            .as_bytes(),
        );
        let row = |file_name: String, data: Vec<u8>| ConfigRow {
            file_name,
            part_no: 0,
            data_size: data.len() as i64,
            binary_hex: encode_hex_for_test(&data),
        };
        let rows = vec![
            row(format!("{configuration_uuid}.0"), module.clone()),
            row(format!("{configuration_uuid}.5"), module.clone()),
            row(format!("{configuration_uuid}.6"), module.clone()),
            row(format!("{configuration_uuid}.7"), module),
            row(format!("{configuration_uuid}.4"), parent_configurations),
            row(format!("{configuration_uuid}.f"), standalone),
            row(role_uuid.to_string(), role_metadata),
        ];

        let dumped = dump_table_rows(&root, "Config", rows, false, false, false).unwrap();

        assert_eq!(dumped.metadata_xml_rows, 0);
        assert_eq!(dumped.source_asset_rows, 2);
        let xml = fs::read_to_string(root.join("Ext/StandaloneConfigurationContent.bin")).unwrap();
        assert!(xml.contains("<Metadata>Role.TargetMetrics</Metadata>"));
        assert!(!xml.contains(role_uuid));
        assert!(!root.join("ConfigDumpInfo.xml").exists());

        let _ = fs::remove_dir_all(root);
    }

