        let (column_formats, formats) = parse_moxel_formats(
            &["3", "{0}", "{128,111}", "{128,222}"],
            1,
            false,
            &[],
            &[],
            &BTreeSet::new(),
            &[],
        );

        assert_eq!(column_formats.len(), 1);
        assert_eq!(column_formats[0].width, Some(222));
        assert_eq!(formats.len(), 2);
