    #[test]
    fn spreadsheet_pack_extract_does_not_promote_field_back_color_style_ref_to_extra_line() {
        let xml = br#"<?xml version="1.0" encoding="UTF-8"?>
<document xmlns="http://v8.1c.ru/8.2/data/spreadsheet" xmlns:v8ui="http://v8.1c.ru/8.1/data/ui" xmlns:xsi="http://www.w3.org/2001/XMLSchema-instance">
	<columns>
		<size>1</size>
	</columns>
	<rowsItem>
		<index>0</index>
		<row>
			<empty>true</empty>
		</row>
	</rowsItem>
	<defaultFormatIndex>4</defaultFormatIndex>
	<line width="1" gap="false">
		<v8ui:style xsi:type="v8ui:SpreadsheetDocumentCellLineType">None</v8ui:style>
	</line>
	<line width="1" gap="false">
		<v8ui:style xsi:type="v8ui:SpreadsheetDocumentCellLineType">Solid</v8ui:style>
	</line>
	<line width="1" gap="false">
		<v8ui:style xsi:type="v8ui:SpreadsheetDocumentCellLineType">Dotted</v8ui:style>
	</line>
	<format>
		<border>0</border>
	</format>
	<format>
		<bottomBorder>1</bottomBorder>
	</format>
	<format>
		<verticalAlignment>Top</verticalAlignment>
		<backColor>style:FieldBackColor</backColor>
	</format>
	<format>
		<width>30</width>
	</format>
</document>
"#;

        let packed = pack_moxel_spreadsheet_blob_from_xml(xml).unwrap();
        let extracted =
            extract_moxel_spreadsheet_xml(&packed.blob, &BTreeMap::new()).expect("extract");

        assert_eq!(
            extracted
                .matches("<line width=\"1\" gap=\"false\">")
                .count(),
            3
        );
        assert!(extracted.contains("<backColor>style:FieldBackColor</backColor>"));
    }

    #[test]
    fn formats_moxel_web_colors_embedded_styles_and_details_use() {
        let style_refs = parse_moxel_style_refs(
            &[
                "{3,1,{4,0,{0},1,2,0,f527dc88-1d39-40b3-bcbb-d98b690ead68,0},0}",
                "{3,3,{-1}}",
                "{3,3,{-3}}",
                "{3,3,{-10}}",
                "{3,2,{121}}",
                "{3,2,{21}}",
            ],
            &BTreeMap::new(),
        );

        assert_eq!(style_refs[0].as_deref(), Some("moxel:f527:1:2"));
        assert_eq!(style_refs[1].as_deref(), Some("style:FormBackColor"));
        assert_eq!(style_refs[2].as_deref(), Some("style:FormTextColor"));
        assert_eq!(style_refs[3].as_deref(), Some("style:FieldBackColor"));
        assert_eq!(style_refs[4].as_deref(), Some("d3p1:RoyalBlue"));
        assert_eq!(style_refs[5].as_deref(), Some("d3p1:Crimson"));
        assert_eq!(moxel_details_use(0), Some("Cell"));
        assert_eq!(moxel_details_use(1), Some("Row"));
        assert_eq!(moxel_details_use(2), Some("WithoutProcessing"));
    }

